public async Task<Result<bool>> Handle(
    EventGuestInviteCommand request,
    CancellationToken cancellationToken)
{
    try
    {
        var nameError = SchedulingLinkHelper.ValidateGuestName(request.Model.GuestFullName);
        if (nameError is not null)
            return nameError;

        var phoneError = SchedulingLinkHelper.ValidatePhone(request.Model.GuestPhoneNumber);
        if (phoneError is not null)
            return phoneError;

        var userId = currentUser.UserId();
        var calendarEvent = await context.CalendarEvents
            .Include(x => x.Calendar)
            .FirstOrDefaultAsync(x => x.Id == request.Model.EventId, cancellationToken);

        if (calendarEvent is null)
            return EventErrors.NotFound;

        var positionIds = await CalendarAccessHelper.GetUserPositionIdsAsync(
            context, userId, cancellationToken);

        if (!await CalendarAccessHelper.CanEditEventAsync(
                calendarEvent, userId, currentUser, positionIds, cancellationToken))
            return EventErrors.EditForbidden;

        await context.GuestContacts.AddAsync(new GuestContact
        {
            EventId = calendarEvent.Id,
            CreatedByUserId = userId,
            FullName = request.Model.GuestFullName.Trim(),
            PhoneNumber = request.Model.GuestPhoneNumber.Trim()
        }, cancellationToken);

        await context.SaveChangesAsync(cancellationToken);
        return Result<bool>.Success(true);
    }
    catch (Exception ex)
    {
        Log.Error($"EventGuestInvite: {ex.Message}", ex);
        return Error.ServerError;
    }
}

